class Solution:
    def isCovered(self, ranges, left, right):
        diff = [0] * 53
        for a, b in ranges:
            diff[a] += 1
            diff[b + 1] -= 1
        cur = 0
        cov = [0] * 53
        for i in range(1, 51):
            cur += diff[i]
            cov[i] = cur
        for x in range(left, right + 1):
            if cov[x] <= 0:
                return False
        return True

