var isCovered = function(ranges, left, right) {
    const diff = new Array(53).fill(0);
    for (const [a, b] of ranges) {
        diff[a] += 1;
        diff[b + 1] -= 1;
    }
    const cov = new Array(53).fill(0);
    let cur = 0;
    for (let i = 1; i <= 50; i++) {
        cur += diff[i];
        cov[i] = cur;
    }
    for (let x = left; x <= right; x++) {
        if (cov[x] <= 0) return false;
    }
    return true;
};
